INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-NOB', 'のぼらん棒®', '脚立を使用せずに、吊りボルトへのケーブルハンガー(結束バンド付)の取り付け、取り外しができます。また、ケーブルの配線、配線後のバンドの結束、解除もできます。パイプはスライド式で収納できるため、コンパクトで取り扱いがラクに行えます。ケーブルハンガー(結束バンド付)用。伸縮幅: 1100~1800mm。直径: φ26.4。', 7520, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-NOB', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
