INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-LAN1', 'ケーブルハンガー (LAN用)', '二重天井等、吊りボルトへのLANケーブルの取り付け(支持)に使用します。吊りボルトへの取り付けワンタッチ! 結束バンド不要! ケーブルを差し込むだけです。配線方向のみに引っ張ることができるのでケーブルがたるみません。SCH-P1が取り付けられます。許容静荷重: 9.8N(1kgf)。適合ボルト: W3/8-W1/2-M10-M12。', 81, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-LAN1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 20, 32.5, 4);
