INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-LF', 'ロックバンド(吊りボルト用)', '樹脂管やケーブル等を吊りボルトに保持する場合に使用します。バンドが自在調整できるので、様々な配線類に使用できます。工具不要!クリップを回転させるだけでボルトへの固定が簡単にできます。バンドを回転できるので様々な配管方向に対応できます。保温材を潰さず固定できる25mm幅の幅広バンド。(ドレンアップホース等保温材付配管の固定にも便利です。)許容静荷重: 20N(2kgf)。適合ボルト: W3/8。適合径: φ30～φ50。', 330, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-LF', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 25, 30, 118);
