INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'GGD-1', '一点どめ台座(鋲打機用)', '別売の専用付属品「吊りボルトアタッチメント」「360°アタッチメント」を使用し、天井からのボルトの吊り下げに使用します。鋲打ち機固定タイプなのでスピーディーに施工ができます。(ビス固定もできます。)許容静荷重: 49N(5kgf)。適合: GGDA-3, GGDA-360。', 160, 'https://dummyimage.com/200x200/cccccc/000.png&text=GGD-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 56, 30, 43);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'GGDA-3', '吊りボルトアタッチメント', '一点どめ台座にはめ込み、ボルトを吊り下げる場合に使用します。許容静荷重: 49N(5kgf)。適合ボルト: W3/8。', 150, 'https://dummyimage.com/200x200/cccccc/000.png&text=GGDA-3', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 39.7, 22, 40);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'GGDA-360', '360°アタッチメント', '一点どめ台座にはめ込み、ボルトを吊り下げる場合に使用します。固定したボルトを自在に可動させ、締結することで対象物の安定性を高める斜材として使用できます。許容静荷重: 49N(5kgf)。適合ボルト: W3/8。', 320, 'https://dummyimage.com/200x200/cccccc/000.png&text=GGDA-360', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 43, 22, 50);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FDK-3', 'ボルト交差クリップ', 'ボルト同士を工具無しで角度自在に交差固定できる樹脂製クリップです。別売の「一点どめ台座」と「吊りボルトアタッチメント」「360°アタッチメント」を組み合わせて使用します。', 140, 'https://dummyimage.com/200x200/cccccc/000.png&text=FDK-3', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 37, NULL, 29.6);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BKG-3', 'ボルト固定具', '天井からのボルトの吊り下げに使用します。壁面への取り付けも可能です。天井に固定し、ボルトを差し込むだけの簡単施工。さらにボルトをねじ込むと回り止めになります。鋲打機固定タイプなのでスピーディーに施工ができます。', 320, 'https://dummyimage.com/200x200/cccccc/000.png&text=BKG-3', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 80, NULL, 60);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'GGBK-3', 'ボルト固定具 (鋲打機用)', '天井からのボルトの吊り下げに使用します。壁面への取り付けも可能です。天井に固定し、ボルトを差し込むだけの簡単施工。さらにボルトをねじ込むと回り止めになります。鋲打機固定タイプなのでスピーディーに施工ができます。', 340, 'https://dummyimage.com/200x200/cccccc/000.png&text=GGBK-3', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 80, NULL, 60);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'GGBKS-3', 'ボルト固定具 (鋲打機用)', '天井からのボルトの吊り下げに使用します。鋲打機固定タイプなのでスピーディーに施工ができます。', 240, 'https://dummyimage.com/200x200/cccccc/000.png&text=GGBKS-3', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 20, 36.5, 44);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'GGSS-3', 'ボルト水平支持具 (鋲打機用)', 'ボルトを水平に取り付ける場合の支持具として使用します。連続使用で、ボルトの支持間隔が長くなった場合の後付け補強や、ボルトを天井面や壁面からはみ出して取り付ける施工等、様々な施工に対応できます。鋲打機固定タイプなのでスピーディーに施工ができます。', 160, 'https://dummyimage.com/200x200/cccccc/000.png&text=GGSS-3', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 64, 33, 25.8);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FDKT-3', '吊り機器用耐震振れ止め部材 ガチタフ® (グレー)', 'パッケージエアコン等の吊りボルトの振れ止めに使用します。1部材でコーナー部も交差部も施工が可能なので、施工時や発注時に部材を迷うことがありません。(20個でパッケージエアコン1台分の施工ができます。)工具不要!固定バーを差し込むだけの簡単施工!軽量(樹脂製)なので現場での運搬、高所作業もラクに行えます。震度7相当!兵庫県南部地震(阪神大震災)再現波の1.2倍の耐震試験にて振れ抑制効果確認!', 280, 'https://dummyimage.com/200x200/cccccc/000.png&text=FDKT-3', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 68, 52.5, 35.5);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FDKT-3K', '吊り機器用耐震振れ止め部材 ガチタフ® (黒)', 'パッケージエアコン等の吊りボルトの振れ止めに使用します。1部材でコーナー部も交差部も施工が可能なので、施工時や発注時に部材を迷うことがありません。(20個でパッケージエアコン1台分の施工ができます。)工具不要!固定バーを差し込むだけの簡単施工!軽量(樹脂製)なので現場での運搬、高所作業もラクに行えます。震度7相当!兵庫県南部地震(阪神大震災)再現波の1.2倍の耐震試験にて振れ抑制効果確認!', 340, 'https://dummyimage.com/200x200/cccccc/000.png&text=FDKT-3K', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 68, 52.5, 35.5);
