INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-GT', 'ケーブルハンガー用 接着剤 (強力型 無溶剤 弾性接着剤) (135ml)', 'ケーブル支持具の接着に最適です。硬化が速い弾性速乾型(ゴム系代替え)です。使い易い一液・常温硬化。内装用途(壁、床)にも使用できます。厚生労働省指針14物質を使用しておりません。コンクリートにも使用できます。', 1790, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-GT', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
