INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-PS', 'ペッタンスティック®', '脚立を使用せずにバインドハンガー、ストリングハンガーを天井に貼り付けられます。', 5140, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-PS', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, 1740, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-4', 'バインドハンガー® (接着タイプ) SCH-4型 (グレー)', '二重天井を吊る前の先行配線に最適なケーブル用ハンガーです。接着剤固定タイプですから施工場所を選びません。カラー3色!配線経路の識別ができます。(一部商品を除く)カラーインサート(NK-3□)にもビス固定できます。耐火被覆を吹き付けてもケーブルが埋もれません。(バインド線180mmタイプ)梁・各種配管資材等を回避して配線作業ができます。(バインド線500mmタイプ)ペッタンスティック(SCH-PS)対応品は、脚立を使用せず天井に貼り付けできます。コンパクトで配線スペースが狭い場所等に最適です。', 69, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-4', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 40, 30, NULL);
