INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-BT210', 'バインドハンガー® (エコノミー連結タイプ)', '二重天井を吊る前の先行配線等に使用するケーブル用ハンガーです。剥離紙から製品だけを片手で剥がせますから高所作業等に最適です。連結タイプなので一個ずつ剥離紙を剥がす手間が省け、作業がスピーディー。使用後も残った剥離紙をまとめて処分できます。強力テープ付ですから、即時施工ができます。', 2670, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-BT210', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 56, 310, 20);
