INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-SW2', 'ケーブルWホルダー (分割タイプ)接着タイプ', '全高が低いのでGL工法やリフォーム工事など配線空間の少ない部分での作業に最適なケーブル用支持具です。バインド線でもケーブルを固定できます。ケーブルWホルダーを半分に切り離し、分割して使用することもできます。接着剤固定タイプですから施工場所を選びません。', 120, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-SW2', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 40, 30, 11.5);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-SW2N', 'ケーブルWホルダー (分割タイプ)接着タイプ', '全高が低いのでGL工法やリフォーム工事など配線空間の少ない部分での作業に最適なケーブル用支持具です。バインド線でもケーブルを固定できます。ケーブルWホルダーを半分に切り離し、分割して使用することもできます。接着剤固定タイプですから施工場所を選びません。', 240, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-SW2N', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 40, 30, 11.5);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-B4', 'バインドハンガー® (丸バインドタイプ)接着タイプ', '天井面や壁面への先行配線等に使用するケーブル用ハンガーです。接着剤固定タイプですから施工場所を選びません。丸バインドタイプなのでケーブルがシッカリ固定できます。製品同士を連結できますので配線が集中する箇所で配線を整列できます。間柱など壁面への固定もできるようビス穴が設けてあります。', 52, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-B4', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 40, 40, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-7', 'ケーブルハンガー (接着剤・粘着テープ併用タイプ)', '二重天井を吊る前の先行配線に最適なケーブル用ハンガーです。接着剤と粘着テープ併用タイプですから、接着剤を塗布し、即時施工ができます。', 240, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-7', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 83, 87.5, 44);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-7N', 'ケーブルハンガー (接着剤・粘着テープ併用タイプ)', '二重天井を吊る前の先行配線に最適なケーブル用ハンガーです。接着剤と粘着テープ併用タイプですから、接着剤を塗布し、即時施工ができます。SCH-7Nは、ワンプッシュで接着剤が塗布できる接着剤入ボトル付!', 500, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-7N', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 83, 87.5, 44);
