INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SDB-3DY', 'フラットデッキ用 ボルト固定具 (カラー台座付)', 'フラットデッキ等への吊りボルトの取り付けに使用します。カラー台座付は、ボルトの回り止め機能付なのでナット不要。色: 黄。適合ボルト: W3/8。', 110, 'https://dummyimage.com/200x200/cccccc/000.png&text=SDB-3DY', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 22, 26, 52.8);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-SB2', 'バインドハンガー®(断熱材用) 断熱材壁面用', '断熱材壁面への先行配線等に使用するケーブル用ハンガーです。バインドハンガーのツメを断熱材(発泡ポリスチレン、ウレタンフォーム等)に押し込むだけの簡単施工!断熱材からケーブルを浮かせて固定できます。(ケーブルが断熱材に直接触れません。)バインドハンガーを半分に切り離し、分割して使用することもできます。バインド線長さ: 130mmx2本。適用: 断熱材厚(20mm以上)。', 64, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-SB2', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, 16, 44);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-SB1', 'バインドハンガー®(断熱材用) (バインド線付)', '断熱材壁面(天井面)への先行配線等に使用するケーブル用ハンガーです。断熱材にねじ込むだけでOKです。断熱材からケーブルを浮かせて固定できます。(ケーブルが断熱材に直接触れません。)種類: バインド線付(長さ: 130mm)。断熱材厚: 20mm以上。', 71, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-SB1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 22, 10, NULL);
