INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DNT-S', '断熱材用サドル 断熱材壁面用', '断熱材への先行配線等に使用するケーブル用サドルです。ケーブルをはめ込みサドルのツメを断熱材(発泡ポリスチレン、ウレタンフォーム等)に押し込むだけの簡単施工!断熱材からケーブルを浮かせて固定できます。(ケーブルが断熱材に直接触れません。)断熱材厚: 20mm以上。適合ケーブル: VVFケーブル(1.6×2C・3C, 2.0×2C・3C)。', 36, 'https://dummyimage.com/200x200/cccccc/000.png&text=DNT-S', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 18, 16, 40);
