INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MCH-1', 'ケーブルハンガー (多機能タイプ)', '仮設現場の単管やワイヤーにボルトを利用し、仮設ケーブルを配線する場合に使用します。単管径Φ48.6、ボルトW3/8、メッセンジャーワイヤー径8~22sq(Φ3.5~Φ6.5)に対応。', 240, 'https://dummyimage.com/200x200/cccccc/000.png&text=MCH-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 66.6, NULL, 16);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KSTH', 'ケーブルハンガー (仮設用)', '仮設現場での単管やワイヤー等を利用して、ケーブル等を取り付ける場合に使用。単管やワイヤーに引っ掛けるだけの簡単取り付け。ケーブルハンガーをねじで連結することにより、2連、3連吊りが可能。直接、壁面への固定も可能。適合径Φ48.6。', 430, 'https://dummyimage.com/200x200/cccccc/000.png&text=KSTH', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KSTH-L', 'ケーブルハンガー (仮設用)', '仮設現場での単管やワイヤー等を利用して、ケーブル等を取り付ける場合に使用。単管やワイヤーに引っ掛けるだけの簡単取り付け。ケーブルハンガーをねじで連結することにより、2連、3連吊りが可能。直接、壁面への固定も可能。適合径Φ105。', 500, 'https://dummyimage.com/200x200/cccccc/000.png&text=KSTH-L', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, 105, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KSTHC', 'ケーブルハンガー (仮設用) (被覆付)', '仮設現場での単管やワイヤー等を利用して、ケーブル等を取り付ける場合に使用。単管やワイヤーに引っ掛けるだけの簡単取り付け。ケーブルハンガーをねじで連結することにより、2連、3連吊りが可能。直接、壁面への固定も可能。被覆付は、ケーブル支持部に樹脂被覆が施してある為、ケーブルを傷めません。適合径Φ48.6。', 570, 'https://dummyimage.com/200x200/cccccc/000.png&text=KSTHC', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
