INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MPBSP-10', 'パワーバンド用スペーサー', 'パワーバンドで、ポール等に管を固定する場合に使用。高所作業時にバンドが容易に外れない仮保持機能付。耐候性に優れ、屋外での使用に最適。貫通穴に六角ボルト(M5)を差し込めば、ボルトを利用して(露出)ボックス等を取り付け可能。色:黒。適合:パワーバンド(MPB-10-M)、ポールバンド樹脂タイプ(POB10P-25M)。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MPBSP-10', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 32, 8, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MPBSP-15', 'パワーバンド用スペーサー', 'パワーバンドで、ポール等に管を固定する場合に使用。高所作業時にバンドが容易に外れない仮保持機能付。耐候性に優れ、屋外での使用に最適。貫通穴に六角ボルト(M5)を差し込めば、ボルトを利用して(露出)ボックス等を取り付け可能。色:黒。適合:パワーバンド(MPB-15-M)。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MPBSP-15', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 89, 8, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MPBB-10', 'パワーバンド用サドルベース', '壁面に、パワーバンドで管を固定する場合に使用。ポール等に管を固定する場合にも使用可能。耐候性に優れ、屋外での使用に最適。色:黒。適合パワーバンド:MPB-10-M。適合ねじ:ねじ径Φ5迄(頭部径Φ9迄)。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MPBB-10', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 40, 17, NULL);
