INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'CGT-50', 'ケーブルガードチューブ', '断熱材(発泡ポリスチレン、ウレタンフォーム)等への接触によるケーブルの侵食を防止。必要な長さだけ箱から引き出して使用できるので作業がラクでムダもない。幅50mm、100mmの広口チューブ。持ち運びに便利なコンパクトな箱入。規格:幅50mm×200m巻。', 2840, 'https://dummyimage.com/200x200/cccccc/000.png&text=CGT-50', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 50, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'CGT-100', 'ケーブルガードチューブ', '断熱材(発泡ポリスチレン、ウレタンフォーム)等への接触によるケーブルの侵食を防止。必要な長さだけ箱から引き出して使用できるので作業がラクでムダもない。幅50mm、100mmの広口チューブ。持ち運びに便利なコンパクトな箱入。規格:幅100mm×200m巻。', 5680, 'https://dummyimage.com/200x200/cccccc/000.png&text=CGT-100', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 100, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'CGW-40', 'ケーブルガード (木胴縁用)', '木胴縁にケーブル、合成樹脂製可とう管等を貫通させる場合に、木胴縁への釘打ちからケーブルを保護する場合に使用。ツメ付で木胴縁にシッカリ取り付け可能。手でカシメられる半割れタイプで施工も簡単。配管された後からでも取り付け可能。適合:ケーブル(Φ17迄)。下穴:Φ21。', 110, 'https://dummyimage.com/200x200/cccccc/000.png&text=CGW-40', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 40, 60, NULL);
