INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'CGW-75P16', 'ケーブルガード (木胴縁用)', '木胴縁にケーブル、合成樹脂製可とう管等を貫通させる場合に、木胴縁への釘打ちからケーブルを保護する場合に使用。ツメ付で木胴縁にシッカリ取り付け可能。手でカシメられる半割れタイプで施工も簡単。配管された後からでも取り付け可能。適合:CD管・PF管(サイズ16以下)・TLフレキ(サイズ16以下)。下穴:Φ28。', 170, 'https://dummyimage.com/200x200/cccccc/000.png&text=CGW-75P16', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 40, 75, NULL);
