INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'CGW-50T', 'ケーブルガード (木胴縁用) (端部用)', '木胴縁にケーブル、合成樹脂製可とう管等を貫通させる場合に、木胴縁への釘打ちからケーブルを保護する場合に使用。ツメ付で木胴縁にシッカリ取り付け可能。手でカシメられる半割れタイプで施工も簡単。配管された後からでも取り付け可能。適合ケーブル径:WFケーブル×1 Φ2.0×3C以下。下穴:20×10。', 100, 'https://dummyimage.com/200x200/cccccc/000.png&text=CGW-50T', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 40, 50, NULL);
