INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBT', 'スライドTLボックス®', '電話・TV・インターホン・チャイム等の配管用の端末、中継ボックスに使用します。受け口のツメにより差し込むだけで、ガッチリ接続できます。アルミ箔付。スリーブ2個付。', 640, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBT', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 55, 55, 36);
