INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBG-1F-K', '鋼製カバー付スライドボックス (省令準耐火対応キット) (センター磁石付) (浅形(深さ30mm)) (1ヶ用)', '省令準耐火構造の住宅に対応したスイッチボックスと耐火ブッシングがセットになったキット品です。鋼製カバーのボックス取り付け穴が最初から不燃材で養生されています。ボックス穴を小判穴ホルソーであけるセンター磁石付です。耐火ブッシングは、熱膨張材なので、300℃以上の熱を受けると2倍以上に膨らみ火災時の延焼を防止します。', 500, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBG-1F-K', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 73, 83, 30);
