INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBTV-3HDF-K', '鋼製カバー付ユニットボックス28 (省令準耐火対応キット)', '省令準耐火構造の住宅に対応した、壁掛けテレビの配線に最適なボックスです。HDMI、LAN、同軸等複数のケーブル配線に対応するサイズ28の波付管が最大8本接続できます。鋼製カバーのボックス取り付け穴が最初から不燃材で養生されています。センター磁石付なので小判穴ホルソーでの穴あけが簡単です。適合管: PF単層波付管(28)×8、CD管(28)×8。', 5260, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBTV-3HDF-K', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 228, 238, 50);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MTKB-TB16', 'タイカブラック 耐火ブッシング', '鋼製カバー付スライドボックス側面ノックのケーブル通線部に使用します。熱膨張材なので、300℃以上の熱を受けると2倍以上に膨らみ火災時の延焼を防止します。適合ノック径: φ21~φ22。適合ボックス厚: ~2mm。適合ケーブル: VVF 1.6×3C-2条 (1ブッシング当り)、VVF 2.0×3C-1条、11以下の通信線・ケーブル。', 150, 'https://dummyimage.com/200x200/cccccc/000.png&text=MTKB-TB16', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 28, 28, 26);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SB-TD23F', '鋼製高台座', '片壁が先に施工されている箇所にスライドボックスを取り付ける場合に使用します。ボックス用: なベタッピンねじ (3.5×14)×2本付。柱用: ワッシャー付ねじ (L=25)×2本付。適用: スライドボックス、鋼製カバー付スライドボックス。', 260, 'https://dummyimage.com/200x200/cccccc/000.png&text=SB-TD23F', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, 170, 30);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBA-1F', '鋼製キャップ付SBアダプター', '鋼製カバー付スライドボックス側面ノックへのTLフレキ・CD管・PF管の取り付けに使用します。適合管(サイズ): TLフレキ 14-16、CD単層波付管 14-16、PF単層波付管 14-16。', 120, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBA-1F', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 27, 27, 31.5);
