INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBP-1A', '気密・遮音パネルボックス (1ヶ用)', '壁厚:4~30㎜迄OK! 色: モダンホワイト。適合仕切板。寒冷地等のスイッチ、コンセントの気密処理が簡単に行えます。スライドツメがガッチリボックスを固定します。遮音効果にも優れています。空気の流入・流出を防ぐので、クリーンルームに使用できます。', 820, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBP-1A', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 70, 120, 40);
