INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBA-U1', 'SB変換アダプタ (サイズ22のノック・受け口用)', 'サイズ22の受け口及びノックに14・16の波付管を取り付ける場合の変換アダプタです。適合管(サイズ): TLフレキ・CD単層波付管・PF単層波付管(14-16)。', 48, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBA-U1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 32, 30, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBA-36', 'SBアダプター (36用)', 'スライドボックスにサイズ36の波付管を接続する場合に使用します。HDMI、LAN、同軸などのケーブルが配管できるため、壁掛けテレビの壁裏配管に最適です。適用: 当社スライドボックス(ノックBのみ)。適合管: PF単層波付管(36), CD単層波付管(36)。', 360, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBA-36', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 51.3, 48.1, 51.3);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SBA-W1', 'SBめがねアダプター (19・21ノック兼用)', '波付管の並列2本配管ができるSBアダプターです。(SBA-W1はだるまミラフレキSSが取り付けられます。)ボックスの中間ノックに取り付けられます。色: 青。適合管(サイズ): TLフレキ 14-16, CD単層波付管 14-16, PF単層波付管 14-16。適合スライドボックス: 2ヶ用以上。', 88, 'https://dummyimage.com/200x200/cccccc/000.png&text=SBA-W1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 50, 30, 6);
