INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'NBS-6', 'スライドアッター', '磁石が壁の奥からスライドする(引き寄せられる)ので、磁石探知距離が浅くなり、壁から離れたボックスも、より正確に探知できます。適合スライドボックス: 深さ36mm用。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=NBS-6', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, 32.5, 15);
