INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PHD-95T', '巾木ダクト', 'プラスチック製。色: チョコレート。全長:2m。軽量で持ち運びや施工がラク。仕切りがあり弱電、強電に分けて配線可能。ワンタッチではめ込み式の蓋で取り付け取り外しが簡単。ケーブルの出し入れや保守点検がラク。', 5960, 'https://dummyimage.com/200x200/cccccc/000.png&text=PHD-95T', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, 90, 23);
