INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SWP-1', '簡易防水カバー', 'キッチン周りのコンセントへの水はねからの保護、日常使用しないコンセントからの隙間風の軽減やホコリの付着防止に使用します。貼るだけの簡単取り付け! 粘着ゲルを使用しているので、繰り返し貼り付けられます。', 420, 'https://dummyimage.com/200x200/cccccc/000.png&text=SWP-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 60, 110, NULL);
