INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'POB-F', 'ポールバンド (ステンレスバンド用)', 'ステンレスバンドを取り付け、鋼管やコンクリート柱等に取り付けられるポールバンドです。各種ボックス・器具等が木ねじで簡単に取り付けられます。クランプやステーはもちろん、鋼管等への穴あけ、溶接も不要です。このままでラクダシポール(MRD-63Y)に取り付けられます。(ラクダシポールに付属のボックス固定金具を使用。(POB-F、POB-1Fは除く))', 170, 'https://dummyimage.com/200x200/cccccc/000.png&text=POB-F', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 73, 66.7, 38.2);
