INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BWZ-1', '引き出すぞう® (強い樹脂製ドレンホースケース)', 'ドレンホースの長期使用に最適なプラ段ケースです。輸送時の箱のつぶれを防止します。ドレンホースの箱のまま入れるだけ。滑り止めシート付! ケースを屋根等に置いたときに滑り落ちるのを防止します。適合(ドレンホース) BWH-14型、BWH-16型。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=BWZ-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 420, 440, 240);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BWHC-1416', 'ネオクリア® (ルームエアコン用消音防虫バルブ)', '屋内外の気圧差によってドレンホース等から外気が流入することで発生するルームエアコンのポコポコ音を解消する消音防虫兼用バルブです。ドレンホースの先端、途中、ドレンパイプ、VP管の先端に使用できます。逆止弁のシリコーンゴムが、内側からの水の流れに対して360°どこでも開く為、排水性に優れ、垂直配管、斜め配管、ころがし配管に対応でき、目詰まりも起こしにくくなっています。逆止弁のシリコーンゴムは外側からは開かない為、小さな虫の侵入、外気の流入や砂埃や異臭もブロックします。クリアーな透明色の為、内部確認が容易にでき、凹凸の無いスリムな円筒形状により、自然な仕上がりになります。取り付けた状態で、分解、組み付けができます。分解時の開口部が広い為、清掃、メンテナンスも容易にできます。本体及び、逆止弁は高耐候性材料を使用しています。材質 本体:アクリル樹脂 弁:シリコーンゴム。適合ドレンホース 14-16。', 1820, 'https://dummyimage.com/200x200/cccccc/000.png&text=BWHC-1416', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 63, 28, 28);
