INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DPSY-20G', 'ドレンパイプ付属品 掃除口継手', 'ドレン配管の中間部に取り付け、メンテナンス時の掃除口として使用します。掃除口を左右任意の方向に回し、メンテナンスしやすい位置に合わせることができます。ドレン配管の外周に接着剤を均一に塗布し、掃除口継手の奥までシッカリ差し込み、接着固定します。横配管に取り付ける場合は、右図のような方向で取り付けてください。メンテナンス後はキャップを確実に締め、掃除口を水平より下を向かない位置に向けてください。※水漏れする恐れがあります。色:グレー, 適合管(サイズ):VP管(20)・VE管(22)・DP管(20)', 1760, 'https://dummyimage.com/200x200/cccccc/000.png&text=DPSY-20G', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 85, 110, 39);
