INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DPRY-50G', 'ドレン配管伸縮継手(径違い45°Y)', 'ドレン配管を排水用タテ管(VP50)に接続する場合に使用する45°Y分岐継手です。排水用タテ管(VP50)の熱伸縮を考慮した伸縮構造です。接続するドレン配管の方向に合わせて向きを変更できる回転構造です。付属品を使用して枝管に様々な管種・サイズを使用可能です。色:グレー, 適合管(主管):VP50, 適合管(枝管):付属品未使用時 VP25-DP25, ブッシング使用時 ステンフレキ13・VP13・DP14・VE14, 異径アダプター使用時 VP13-DP14-VE14-VP20-DP20-VE22', 3420, 'https://dummyimage.com/200x200/cccccc/000.png&text=DPRY-50G', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 128, 155, 80);
