INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DA-KHS', 'ドレン配管間接排水アダプター (防虫カバー付)', 'ドレンパイプと機器の間に使用し、機器への排水の逆流を防止します。付属の変換アダプターを取り付ければ機器への直接取り付けが可能です。防虫、機器のトラブル予防にも効果を発揮します。色:グレー, 適合ねじ径:R1/2, G1/2, 適合付属品:VP16用・VE16用・DP16用付属品, 適合管:VP13-VE14-DP14', 930, 'https://dummyimage.com/200x200/cccccc/000.png&text=DA-KHS', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 65.5, 88, 36.8);
