INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BWMH-C', 'マルチドレンホース用気密試験キャップ', 'マルチドレンホースの気密試験を行う際に室内機側継手に取り付けて使用するキャップです。適合: マルチドレンホース 室内機側継手 BWMH-7-BWMH-10, BWMH-T7-BWMH-T10, BWMH-10A25-BWMH-10V25/', 660, 'https://dummyimage.com/200x200/cccccc/000.png&text=BWMH-C', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 43, 50, 43);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DPG-4050G', 'ドレンパイプ用逆止弁', '色: グレー, 適合管: VP管・VU管(40·50), エアコン等のドレン排水管に使用する臭気対策用の逆止弁です。弁体部を取り外し、点検・清掃等のメンテナンスが可能です。通常時は磁石の反発によって弁を密閉し、さらに排水を溜めておけるのでダブルで臭気をシャットアウトします。※排水はある程度溜まると自重で弁が開き、排出されていく仕組みです。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=DPG-4050G', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 80, 83.5, 80);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-LF', 'ロックバンド(吊りボルト用)', '樹脂管やケーブル等を吊りボルトに保持する場合に使用します。バンドが自在調整できるので、様々な配線類に使用できます。工具不要! クリップを回転させるだけでボルトへの固定が簡単にできます。バンドを回転できるので様々な配管方向に対応できます。保温材を潰さず固定できる25mm幅の幅広バンド。(ドレンアップホース等保温材付配管の固定にも便利です。)適合径: Φ30~Φ50, 適合ボルト: W3/8', 330, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-LF', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 25, 130, 47);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FLB-T4570M', '保温管用ロックバンド(吊りバンドタイプ)', '色: ミルキーホワイト, 適合径: Φ45~70, 適合管周長(㎜): 141~220, 適合ボルト: W3/8, 冷媒管やファンコイルユニットの保温材付き樹脂管などの保温管専用の吊りバンドです。長さ200mmの保護プレートで保温材の潰れを抑制し、2本のロックバンドで保温管を幅広く安定保持できます。工具不要! 吊りボルトにねじ込むだけで取り付けが可能。保護プレートが一体化しているのでプレート落下の心配もありません。ロックバンド方式なのでシングル管やペア管の保持が可能で、幅広い配管径に対応ができます。', 410, 'https://dummyimage.com/200x200/cccccc/000.png&text=FLB-T4570M', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 78, 262, 66);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FLB-T4570K', '保温管用ロックバンド(吊りバンドタイプ)', '色: 黒, 適合径: Φ45~70, 適合管周長(㎜): 141~220, 適合ボルト: W3/8, 冷媒管やファンコイルユニットの保温材付き樹脂管などの保温管専用の吊りバンドです。長さ200mmの保護プレートで保温材の潰れを抑制し、2本のロックバンドで保温管を幅広く安定保持できます。工具不要! 吊りボルトにねじ込むだけで取り付けが可能。保護プレートが一体化しているのでプレート落下の心配もありません。ロックバンド方式なのでシングル管やペア管の保持が可能で、幅広い配管径に対応ができます。', 500, 'https://dummyimage.com/200x200/cccccc/000.png&text=FLB-T4570K', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 78, 262, 66);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FDKT-3', '吊り機器用耐震振れ止め部材 ガチタフ', '色: グレー, 適合ボルト: W3/8, パッケージエアコン等の吊りボルトの振れ止めに使用します。1部材でコーナー部も交差部も施工が可能なので、施工時や発注時に部材を迷うことがありません。(20個でパッケージエアコン1台分の施工ができます。)工具不要! 固定バーを差し込むだけの簡単施工!軽量(樹脂製)なので現場での運搬、高所作業もラクに行えます。震度7相当!兵庫県南部地震(阪神大震災)再現波の1.2倍の耐震試験にて振れ抑制効果確認!', 280, 'https://dummyimage.com/200x200/cccccc/000.png&text=FDKT-3', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 68, 52.5, 35.5);
