INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'GKPB-67', '防水貫通スリーブ', '色: ベージュ, 取付穴径: Φ75, 壁厚: 200mm迄, 壁板厚: 12mm以上(外壁), 壁穴寸法: Φ75貫通穴, 外壁の内側に、防水シートを貼る場合の防水スリーブです。壁厚に合わせてスリーブをカットして使用します。(溝付なのでニッパでカットするだけです。)', 890, 'https://dummyimage.com/200x200/cccccc/000.png&text=GKPB-67', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 90, 213.5, 90);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PSG-S', 'パイプ支持具', '粘着テープ付, 適合管: DP14、VP13、VE14, L: 50, P: 35, ドレンパイプ等を壁貫通する際の管の支持に使用します。管を床から立ち上げる際の貫通穴の化粧にも使用できます。仮固定できる粘着テープ付です。寒暖差等による伸縮にも追従できます。(2面接着)', 300, 'https://dummyimage.com/200x200/cccccc/000.png&text=PSG-S', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 35, 50, 14.5);
