INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PYPFE-100', '換気パイプ用自在エルボ', '樹脂製(ベージュ色)。換気パイプの曲がり、コーナー、段差箇所等に使用します。配管の方向が自在に変えられます。固定ビスにより吊りバンド等の固定ができます。テープ固定ができます。アルミフリーダクトにも使用できます。適合パイプ: 換気パイプ100.', 3630, 'https://dummyimage.com/200x200/cccccc/000.png&text=PYPFE-100', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 90, 90, 195);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PYSB-75', '防水換気スリーブ', '樹脂製(ベージュ色)。外壁の内側に、防水シートを貼る場合に使用します。大型フランジにより、防水シート貫通時のテープによる防水処理が簡単にできます。排水勾配があります。壁厚に合わせてスリーブがカット、調節できる溝付です。壁厚:100mm迄, 壁穴寸法:Φ85貫通穴. 適合: パイプフード:接続部Φ75.', 1350, 'https://dummyimage.com/200x200/cccccc/000.png&text=PYSB-75', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 120, 130, 236.5);
