INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PYU-75', 'パイプアッター', 'パイプ探知用磁石。パイプ等に取り付け、壁施工後の穴あけポイント探知に使用します。パイプ径に合わせてスライド調整。穴あけ後は、繰り返し使用できます。磁石探知距離:40mm. 適合パイプ(内径):Φ50, Φ75.', 1000, 'https://dummyimage.com/200x200/cccccc/000.png&text=PYU-75', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
