INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PYSB-S100', '鋼製防水換気スリーブ', '適合: パイプフード: 接続部φ100, アルミフリーダクト: AFD-100, 換気パイプ: PYP-100J-100J4. 規格: 壁厚:110mm迄, 壁穴寸法:105貫通穴. 外壁の内側に、防水シートを貼る場合に使用します。排水勾配があります。内径100、φ150の換気パイプ等に直接接続することができます。', 6660, 'https://dummyimage.com/200x200/cccccc/000.png&text=PYSB-S100', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 150, 150, 140);
