INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KB-12KP', 'コンパネ支持金具', '適合ボード厚: 12~18mm. せっこうボード壁、二重天井等のボード裏へ補強用コンパネを取り付ける場合に使用します。(換気扇、分電盤、エアコン、トイレットペーパーホルダー、タオル掛け等の取り付け面の補強に便利です。). 許容静荷重:98N (10kgf) 〈2個で1組〉.', 660, 'https://dummyimage.com/200x200/cccccc/000.png&text=KB-12KP', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 70, 48, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AIA-100', '風速増強アタッチメント (シロッコファン(多翼送風機)専用)', '適合ダクトサイズ: 100. 適合管サイズ: 内径98.5, 外径102~107. 開口面積: 9.3c㎡. 工場などの空調用パイプに取り付けることで空調の風速を上げることができます。(風速が上がることで、涼しく快適に作業が行えます。).', 2560, 'https://dummyimage.com/200x200/cccccc/000.png&text=AIA-100', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 111, 111, 34);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AIA-150', '風速増強アタッチメント (シロッコファン(多翼送風機)専用)', '適合ダクトサイズ: 150. 適合管サイズ: 内径148.5, 外径153~157. 開口面積: 50.7c㎡. 工場などの空調用パイプに取り付けることで空調の風速を上げることができます。(風速が上がることで、涼しく快適な作業が行えます。).', 3700, 'https://dummyimage.com/200x200/cccccc/000.png&text=AIA-150', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 161, 161, 34);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MDBP-15', '吊りバンド (樹脂タイプ クルクルパック)', '幅: 15mm, 長さ: 30m, 厚み: 1.2mm. 許容静荷重: 20N (2kgf). アルミフリーダクトや換気パイプ等の吊り下げ支持に使用します。任意の位置(長さ)で切断して使用できます。軽くて丈夫な樹脂タイプ(幅15mm・25mm)と、堅牢な鉄製(幅25mm)があり、使い勝手に応じて選べます。樹脂タイプは、使う分だけ引き出せるクルクルパック仕様です。(途中まで出した余分を巻き戻して収納できる便利な箱です。). 使用温度:60℃迄。', 6060, 'https://dummyimage.com/200x200/cccccc/000.png&text=MDBP-15', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 15, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MDBP-25', '吊りバンド (樹脂タイプ クルクルパック)', '幅: 25mm, 長さ: 30m, 厚み: 1.2mm. 許容静荷重: 20N (2kgf). アルミフリーダクトや換気パイプ等の吊り下げ支持に使用します。任意の位置(長さ)で切断して使用できます。軽くて丈夫な樹脂タイプ(幅15mm・25mm)と、堅牢な鉄製(幅25mm)があり、使い勝手に応じて選べます。樹脂タイプは、使う分だけ引き出せるクルクルパック仕様です。(途中まで出した余分を巻き戻して収納できる便利な箱です。). 使用温度:60℃迄。', 7230, 'https://dummyimage.com/200x200/cccccc/000.png&text=MDBP-25', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 25, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MDB-20', '吊りバンド (鉄製)', '幅: 25mm, 長さ: 20m, 厚み: 0.8mm. 最大耐荷重: 196N (20kgf). 材質:溶融亜鉛めっき鋼板. アルミフリーダクトや換気パイプ等の吊り下げ支持に使用します。任意の位置(長さ)で切断して使用できます。軽くて丈夫な樹脂タイプ(幅15mm・25mm)と、堅牢な鉄製(幅25mm)があり、使い勝手に応じて選べます。', 4990, 'https://dummyimage.com/200x200/cccccc/000.png&text=MDB-20', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 25, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-5B', 'バンドハンガー (吊りバンド固定用 接着剤無)', '適合吊りバンド: MDBP-15, MDB-20, MDBP-25. 天井面等への吊りバンド取り付けに使用します。接着剤固定タイプですから施工場所を選びません。許容静荷重:20N (2kgf).', 50, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-5B', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 40, 40, NULL);
