INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-5BGP', 'バンドハンガー (鋲打機用)', '適合吊りバンド: MDBP-15, MDB-20, MDBP-25. 天井面等への吊りバンドの取り付けに使用します。鋲打機固定タイプですのでスピーディーに施工ができます。コンクリートピンでの固定もできます。許容静荷重:29N(3kgf).', 68, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-5BGP', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 37, 58, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MDB-S', 'バンドサドル (吊りバンド用サドル)', '適合吊りバンド: MDBP-15, 25, MDB-20. 適合ダクト径: φ50~φ150. 吊りバンドによる木柱等へのダクト、換気パイプ等の取り付け(支持)に使用します。', 84, 'https://dummyimage.com/200x200/cccccc/000.png&text=MDB-S', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 32, 39.5, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'GGLB-L150M', 'ロックバンド (鋲打機用)', '適合径: φ20~φ33. 鋲打機で簡単に固定ができる幅ひろ(14㎜)タイプの結束バンドです。ビス固定もできます。許容静荷重:20N (2kgf).', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=GGLB-L150M', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 35, 37.5, NULL);
