INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-L380K', 'ロックバンド', '適合径: φ38~φ110. 木柱等にねじ固定できる丈夫な幅ひろタイプの結束バンドです。許容静荷重:29N(3kgf). 適合ねじ: 呼び4・5. 適合釘: φ2.5以下.', 120, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-L380K', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-M200K', 'ロックバンド (モールダクト60型用)', '適合径: φ35~φ50. 木柱等にねじ固定できる丈夫な幅ひろタイプの結束バンドです。バンドが軟らかいので、モールダクト内での配管固定にも使用できます。(SCH-M200K: モールダクト60型用). 許容静荷重:20N(2kgf). 適合ねじ: 呼び4.', 69, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-M200K', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-M300K', 'ロックバンド (モールダクト100型用)', '適合径: φ50~φ85. 木柱等にねじ固定できる丈夫な幅ひろタイプの結束バンドです。バンドが軟らかいので、モールダクト内での配管固定にも使用できます。(SCH-M300K: モールダクト100型用). 許容静荷重:20N(2kgf). 適合ねじ: 呼び4.', 110, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-M300K', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MDBP-100B2', '黒バンド (吊りバンドタイプ PE製)', '幅: 100mm, 長さ: 30m, 厚み: 0.7mm. バンド幅が広いので配管材への負荷が軽減できます。部材が少なく施工が簡単でスピーディーに行えます。曲げに強く耐久性に優れています。取り出し、収納に便利な段ボールケース入です。保温付フレキダクトにやさしい幅広バンド。部材が少なく施工が速い。付属品は市販の樹脂バンドに対応。許容静荷重:39.2N(4kgf). 使用温度:60℃迄。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MDBP-100B2', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 100, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SVC-FD', 'FDクリップ (黒バンド・樹脂バンド用)', '適合バンド: 黒バンド(MDBP-100B2), 樹脂バンド(穴ピッチ30mm). 黒バンド等でループを作る場合に使用します。許容静荷重:39.2N(4kgf). 使用温度:60℃迄。', 73, 'https://dummyimage.com/200x200/cccccc/000.png&text=SVC-FD', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SVC-FDB', 'FDクリップ (ボルトタイプ 黒バンド・樹脂バンド用)', '適合ボルト: W3/8・W1/2, M10-M12. 適合バンド: 黒バンド(MDBP-100B2), 樹脂バンド(穴ピッチ30mm). 黒バンド等を使用し、吊りボルトに空調用ダクト等を取り付ける場合に使用します。許容静荷重:19.6N(2kgf). 使用温度:60℃迄。', 73, 'https://dummyimage.com/200x200/cccccc/000.png&text=SVC-FDB', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SVC-FD2', 'FDクリップ (重ね止めタイプ 黒バンド・樹脂バンド用)', '適合吊りバンド: 黒バンド(MDBP-100B2), 樹脂バンド(穴ピッチ30mm). 適合ケーブル: VVF1.6×(2C、3C), VVF2.0×(2C、3C). バインドハンガー (鋲打機用)で黒バンドを取り付けた時、黒バンドを巻き固定する場合に使用します。VVFケーブルも取り付けられます。許容静荷重:39.2N(4kgf). 使用温度:60℃迄。', 76, 'https://dummyimage.com/200x200/cccccc/000.png&text=SVC-FD2', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-FDG', 'バンドハンガー (鋲打機用)', '適合バンド: 樹脂バンド (50mm幅、穴ピッチ30mm). 天井面等への樹脂バンドの取り付けに使用します。樹脂バンド取り付け箇所には十分な曲げRが確保してあり、バンドへの負荷が軽減されます。鋲打機固定タイプですのでスピーディーに施工ができます。ビス固定もできます。許容静荷重:39.2N(4kgf). 使用温度:60℃迄。', 71, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-FDG', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 64.3, 70.6, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-FDGW', 'バンドハンガー (鋲打機用)', '適合バンド: 黒バンド(MDBP-100B2), 樹脂バンド(穴ピッチ30mm). 天井面等への樹脂バンドの取り付けに使用します。樹脂バンド取り付け箇所には十分な曲げRが確保してあり、バンドへの負荷が軽減されます。鋲打機固定タイプですのでスピーディーに施工ができます。ビス固定もできます。許容静荷重:39.2N(4kgf). 使用温度:60℃迄。', 100, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-FDGW', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 64.3, 70.6, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-FDB', 'バンドハンガー (ボルトタイプ)', '適合ボルト: W3/8, M10. 適合バンド: 樹脂バンド (50mm幅、穴ピッチ30mm). 吊りボルトへの樹脂バンドの取り付けに使用します。樹脂バンド取り付け箇所には十分な曲げRが確保してあり、バンドへの負荷が軽減されます。許容静荷重:39.2N(4kgf). 使用温度:60℃迄。', 71, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-FDB', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 64.3, 70.6, NULL);
